import{_ as i,o as t,c as a,a2 as r}from"./chunks/framework.Cuq8tsM6.js";const f=JSON.parse('{"title":"3. Validation & Diffusion","description":"","frontmatter":{"title":"3. Validation & Diffusion"},"headers":[],"relativePath":"docs/fr/advertisers/dedicated-email/3-validation-diffusion.md","filePath":"docs/fr/advertisers/dedicated-email/3-validation-diffusion.md"}'),s={name:"docs/fr/advertisers/dedicated-email/3-validation-diffusion.md"};function n(o,e,d,l,p,u){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="etape-3-validation-et-diffusion" tabindex="-1">Étape 3 : Validation et Diffusion <a class="header-anchor" href="#etape-3-validation-et-diffusion" aria-label="Permalink to &quot;Étape 3 : Validation et Diffusion&quot;">​</a></h1><p>La création est terminée ? Il ne reste plus qu&#39;à valider le BAT (Bon à Tirer) pour autoriser l&#39;envoi.</p><hr class="my-6"><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:var(--gi-accent);color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">1</div><div><h3 class="mt-0 text-blue-200">Configuration du Tracking</h3><p>Cette étape est transparente pour vous. L&#39;équipe getinside et le Distributeur intègrent les pixels et les liens de redirection.</p><div style="background:var(--gi-tint-blue-bg);border:1px solid var(--gi-accent);padding:15px;border-radius:6px;"><strong>💡 Rappel important :</strong><br> Vos liens de redirection sont <strong>dynamiques</strong>. Vous pouvez modifier l&#39;URL de destination finale à tout moment (même après la validation) dans l&#39;onglet <strong>&quot;Configuration et Suivi&quot;</strong>. </div></div></div><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:var(--gi-accent);color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">2</div><div><h3 class="mt-0 text-purple-200">Réception du BAT</h3><p>Dès que le Distributeur a finalisé l&#39;email et que nous l&#39;avons vérifié techniquement, vous recevez une notification par email.</p><p>Vous accédez alors à une <strong>prévisualisation statique</strong> de la campagne pour vérifier le respect du brief.</p></div></div><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:var(--gi-tint-red-text);color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">!</div><div><h3 class="mt-0 text-red-200">Votre Validation (Action Requise)</h3><p>Si la création vous convient :</p><div style="border:2px solid var(--gi-tint-red-text);background:var(--gi-tint-red-bg);padding:20px;border-radius:8px;"><h4 class="mt-0 mb-2 text-red-200">⚠️ Pour débloquer l&#39;envoi :</h4><ol class="mb-0"><li>Connectez-vous à <a href="https://app.getinside.media/">app.getinside.media</a>.</li><li>Allez sur la campagne concernée.</li><li>Cliquez sur le bouton <strong>&quot;Valider la campagne&quot;</strong>.</li></ol></div><p class="mt-2 text-grey-dk-000 fs-2"><em>Tant que vous ne cliquez pas, la campagne reste bloquée et ne sera pas diffusée.</em></p></div></div><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:var(--gi-tint-green-text);color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">🚀</div><div><h3 class="mt-0 text-green-200">Diffusion</h3><p>Une fois les deux validations enregistrées (la vôtre + celle du Distributeur), la campagne est programmée.</p><p>Vous pourrez suivre les statistiques (Ouvertures, Clics) directement depuis votre tableau de bord.</p></div></div>',7)])])}const v=i(s,[["render",n]]);export{f as __pageData,v as default};
